// src/pages/ProductDetail.jsx
import React, { useEffect, useState, useContext } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";

import { CartContext } from "../context/CartContext";

const API_URL = "http://localhost:5000/api";

const ProductDetail = () => {
  const { id } = useParams();              // /product/:id
  const navigate = useNavigate();
  const { addToCart } = useContext(CartContext);

  const [product, setProduct] = useState(null);
  const [activeImage, setActiveImage] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // ===== LOAD PRODUCT =====
  useEffect(() => {
    const fetchProduct = async () => {
      try {
        setLoading(true);
        setError("");

        const res = await axios.get(`${API_URL}/products/${id}`);
        const data = res.data?.product || res.data;

        setProduct(data);
        if (data?.images?.length) {
          setActiveImage(data.images[0]);
        }
      } catch (err) {
        console.error(err);
        setError("Không tải được sản phẩm. Vui lòng thử lại.");
      } finally {
        setLoading(false);
      }
    };

    if (id) fetchProduct();
  }, [id]);

  // ===== HANDLERS =====
  const handleAddToCart = () => {
    if (!product) return;
    addToCart(product, quantity);
  };

  const handleBuyNow = () => {
    if (!product) return;
    addToCart(product, quantity);
    navigate("/checkout");
  };

  const handleQuantityChange = (value) => {
    setQuantity((prev) => {
      const next = prev + value;
      if (next < 1) return 1;
      if (product?.stock && next > product.stock) return product.stock;
      return next;
    });
  };

  // ===== UI =====
  if (loading) {
    return (
      <div className="flex flex-col min-h-screen bg-[#fff7f9]">
        <Header />
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <p className="text-[#e06c7f] text-lg animate-pulse">
            Đang tải sản phẩm...
          </p>
        </main>
        <Footer />
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="flex flex-col min-h-screen bg-[#fff7f9]">
        <Header />
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <div className="bg-white px-8 py-6 rounded-2xl shadow border border-pink-100 text-center">
            <p className="text-red-500 mb-2">❌ {error || "Không tìm thấy sản phẩm."}</p>
            <button
              onClick={() => navigate("/product")}
              className="mt-2 px-5 py-2 rounded-full bg-[#e06c7f] text-white text-sm font-semibold hover:bg-[#cc5f72]"
            >
              Quay lại cửa hàng
            </button>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const hasDiscount =
    product.discountPrice && product.discountPrice < product.price;

  return (
    <div className="flex flex-col min-h-screen bg-[#fff7f9]">
      <Header />
      <Navbar />

      <main className="flex-1 max-w-6xl mx-auto px-4 py-8">
        {/* Breadcrumb đơn giản */}
        <p className="text-sm text-gray-500 mb-4">
          Trang chủ / Sản phẩm /{" "}
          <span className="text-[#e06c7f] font-medium">{product.name}</span>
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* LEFT – HÌNH ẢNH */}
          <section className="bg-white rounded-2xl shadow-md border border-pink-100 p-4 flex flex-col gap-4">
            <div className="aspect-square w-full bg-[#fff7fb] rounded-2xl overflow-hidden flex items-center justify-center">
              <img
                src={activeImage || product.images?.[0]}
                alt={product.name}
                className="max-h-full max-w-full object-contain"
              />
            </div>

            {product.images?.length > 1 && (
              <div className="flex gap-3 mt-2 overflow-x-auto pb-1">
                {product.images.map((img, idx) => (
                  <button
                    key={idx}
                    type="button"
                    onClick={() => setActiveImage(img)}
                    className={`w-20 h-20 rounded-xl border overflow-hidden flex-shrink-0 ${
                      activeImage === img
                        ? "border-[#e06c7f] ring-2 ring-[#e06c7f66]"
                        : "border-pink-200 hover:border-[#e06c7f]"
                    }`}
                  >
                    <img
                      src={img}
                      alt={`${product.name} ${idx + 1}`}
                      className="w-full h-full object-cover"
                    />
                  </button>
                ))}
              </div>
            )}
          </section>

          {/* RIGHT – THÔNG TIN */}
          <section className="bg-white rounded-2xl shadow-md border border-pink-100 p-6 flex flex-col gap-4">
            <div className="flex items-start justify-between gap-4">
              <div>
                <h1 className="text-2xl md:text-3xl font-bold text-[#4b2c35] mb-2">
                  {product.name}
                </h1>
                {product.category?.name && (
                  <p className="text-sm text-gray-500">
                    Danh mục:{" "}
                    <span className="text-[#e06c7f] font-medium">
                      {product.category.name}
                    </span>
                  </p>
                )}
                {product.sku && (
                  <p className="text-xs text-gray-400 mt-1">
                    Mã SP: {product.sku}
                  </p>
                )}
              </div>

              {product.rating && (
                <div className="text-right">
                  <p className="text-sm text-[#e06c7f] font-semibold">
                    ★ {product.rating.toFixed(1)} / 5
                  </p>
                  <p className="text-xs text-gray-500">
                    ({product.numReviews || 0} đánh giá)
                  </p>
                </div>
              )}
            </div>

            {/* GIÁ */}
            <div className="mt-2">
              {hasDiscount ? (
                <>
                  <p className="text-3xl font-bold text-[#e06c7f]">
                    {product.discountPrice.toLocaleString("vi-VN")}₫
                  </p>
                  <p className="text-sm text-gray-400">
                    <span className="line-through mr-1">
                      {product.price.toLocaleString("vi-VN")}₫
                    </span>
                    <span className="bg-[#ffe9f0] text-[#e06c7f] px-2 py-0.5 rounded-full text-xs">
                      -{Math.round(
                        ((product.price - product.discountPrice) /
                          product.price) *
                          100
                      )}
                      %
                    </span>
                  </p>
                </>
              ) : (
                <p className="text-3xl font-bold text-[#4b2c35]">
                  {product.price.toLocaleString("vi-VN")}₫
                </p>
              )}
            </div>

            {/* MÔ TẢ NGẮN */}
            {product.description && (
              <p className="text-sm text-gray-700 leading-relaxed mt-2 whitespace-pre-line">
                {product.description}
              </p>
            )}

            {/* SỐ LƯỢNG + STOCK */}
            <div className="mt-4 flex items-center gap-4">
              <div>
                <p className="text-sm text-gray-600 mb-1">Số lượng</p>
                <div className="inline-flex items-center border border-pink-200 rounded-full overflow-hidden bg-[#fff7fb]">
                  <button
                    type="button"
                    onClick={() => handleQuantityChange(-1)}
                    className="w-9 h-9 flex items-center justify-center text-lg text-[#e06c7f]"
                  >
                    -
                  </button>
                  <span className="w-10 text-center text-sm">{quantity}</span>
                  <button
                    type="button"
                    onClick={() => handleQuantityChange(1)}
                    className="w-9 h-9 flex items-center justify-center text-lg text-[#e06c7f]"
                  >
                    +
                  </button>
                </div>
              </div>

              {typeof product.stock === "number" && (
                <p className="text-sm text-gray-500">
                  Còn lại:{" "}
                  <span className="font-semibold text-[#4b2c35]">
                    {product.stock}
                  </span>{" "}
                  sản phẩm
                </p>
              )}
            </div>

            {/* NÚT HÀNH ĐỘNG */}
            <div className="mt-4 flex flex-col sm:flex-row gap-3">
              <button
                type="button"
                onClick={handleAddToCart}
                className="flex-1 px-4 py-3 rounded-full border border-[#e06c7f] text-[#e06c7f] font-semibold hover:bg-[#ffe9f0] transition"
              >
                Thêm vào giỏ
              </button>
              <button
                type="button"
                onClick={handleBuyNow}
                className="flex-1 px-4 py-3 rounded-full bg-[#e06c7f] text-white font-semibold hover:bg-[#cc5f72] transition shadow-sm"
              >
                Mua ngay
              </button>
            </div>

            {/* THÔNG TIN BỔ SUNG */}
            <div className="mt-6 border-t border-pink-100 pt-4 space-y-2 text-sm text-gray-700">
              <p>🚚 Giao hàng nội thành TP.HCM trong ngày cho đơn trước 15h.</p>
              <p>🎁 Miễn phí thiệp & gói quà cho mọi đơn hàng.</p>
              <p>💌 Hỗ trợ chỉnh sửa lời chúc theo yêu cầu.</p>
            </div>
          </section>
        </div>
      </main>

      <Footer />
    </div>
  );
};

export default ProductDetail;
